// === src/components/statement.js ===
'use strict';

/**
 * Stage.Statement — one massive declarative sentence, centered.
 *
 * Usage:
 *   Stage.register(Stage.Statement({
 *     section: 1,
 *     title: '01 · Thesis',
 *     text: 'We are not in the business of making widgets. We are in the business of trust.',
 *     emphasis: ['trust'],   // substrings within text get accent color
 *     color: 'accent'        // 'accent' | 'amber' | 'blue' — controls emphasis color
 *   }));
 *
 * On init the text reveals word by word.
 *
 * Edit paths:
 *   text  (the whole sentence; emphasis is structural, not inline-editable)
 */

(function (root) {
  const Stage = root.Stage = root.Stage || {};

  Stage.Statement = function (opts) {
    const text = opts.text || '';
    const emphasis = Array.isArray(opts.emphasis) ? opts.emphasis : [];
    const color = opts.color || 'accent';

    return {
      section: opts.section,
      title: opts.title,
      transition: opts.transition,
      render(el) {
        el.classList.add('statement-host');
        // Build emphasized HTML, then split by whitespace into word spans so we
        // can stagger reveal. We escape first, then wrap emphasis spans.
        const emphasized = emphasizeHTML(text, emphasis, color);
        const words = splitWords(emphasized);

        el.innerHTML = `
          <div class="statement" data-stage-key="Statement">
            <p class="statement-text" data-stage-edit="text" data-stage-key="Statement/text">${
              words.map((w, i) => `<span class="st-word" data-i="${i}">${w}</span>`).join(' ')
            }</p>
          </div>
        `;
      },
      init(el) {
        const words = el.querySelectorAll('.st-word');
        const timers = [];
        words.forEach((w, i) => {
          timers.push(setTimeout(() => w.classList.add('in'), 120 + i * 90));
        });
        return () => timers.forEach(clearTimeout);
      },
      replay(el) {
        el.querySelectorAll('.st-word').forEach(n => n.classList.remove('in'));
        return this.init(el);
      }
    };
  };

  // Build escaped HTML where each emphasis substring becomes
  // <span class="st-em st-em--accent">...</span>.
  function emphasizeHTML(raw, emphasis, color) {
    let html = escape(raw);
    // Sort longest first so substrings don't shadow longer matches.
    const sorted = [...emphasis].filter(Boolean).sort((a, b) => b.length - a.length);
    for (const phrase of sorted) {
      const esc = escape(phrase);
      const re = new RegExp(escapeRegex(esc), 'g');
      html = html.replace(re, `<span class="st-em st-em--${escape(color)}">${esc}</span>`);
    }
    return html;
  }

  // Split into word tokens, preserving emphasis tags intact (don't split inside <span>).
  function splitWords(html) {
    // Tokenize: keep tag-blocks atomic by splitting on plain whitespace
    // but only outside tags. Simple state machine.
    const tokens = [];
    let buf = '';
    let depth = 0;
    for (let i = 0; i < html.length; i++) {
      const c = html[i];
      if (c === '<') depth++;
      if (c === ' ' && depth === 0) {
        if (buf) tokens.push(buf);
        buf = '';
      } else {
        buf += c;
      }
      if (c === '>') depth--;
    }
    if (buf) tokens.push(buf);
    return tokens;
  }

  function escapeRegex(s) {
    return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  function escape(s) {
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
})(typeof window !== 'undefined' ? window : globalThis);

// === src/components/stats.js ===
'use strict';

/**
 * Stage.Stats — grid of statistic mini-cards.
 *
 * Usage:
 *   Stage.register(Stage.Stats({
 *     section: 6,
 *     title: '06 · The numbers',
 *     blocks: [
 *       { number: 92, unit: '%', label: 'cost-per-token drop', color: 'accent' },
 *       { number: 7,  unit: 'x', label: 'context window growth', color: 'amber' },
 *       { number: 3,  unit: 'd', label: 'avg PR turnaround',     color: 'blue' }
 *     ],
 *     columns: 3                       // optional, defaults to blocks.length up to 4
 *   }));
 *
 * On init each number counts up from 0 → target, staggered by ~200ms.
 *
 * Edit paths: blocks[i].number / blocks[i].unit / blocks[i].label
 */

(function (root) {
  const Stage = root.Stage = root.Stage || {};

  Stage.Stats = function (opts) {
    const blocks = opts.blocks || [];
    const columns = Math.min(4, opts.columns || Math.min(4, blocks.length || 1));

    return {
      section: opts.section,
      title: opts.title,
      transition: opts.transition,
      render(el) {
        el.innerHTML = `
          <div class="stats stats--cols-${columns}" data-stage-key="Stats">
            ${blocks.map((b, i) => `
              <div class="stat ${b.color ? 'stat--' + b.color : ''}" data-stage-key="Stats/block[${i}]">
                <div class="stat-figure">
                  <span class="stat-num" data-stage-edit="blocks[${i}].number" data-target="${Number(b.number) || 0}">0</span>${b.unit ? `<span class="stat-unit" data-stage-edit="blocks[${i}].unit">${escape(b.unit)}</span>` : ''}
                </div>
                <div class="stat-label" data-stage-edit="blocks[${i}].label">${escape(b.label || '')}</div>
              </div>
            `).join('')}
          </div>
        `;
      },
      init(el) {
        const nums = el.querySelectorAll('.stat-num');
        const cards = el.querySelectorAll('.stat');
        const duration = 1200;
        const stagger = 200;
        const rafs = [];
        const timers = [];
        cards.forEach((card, i) => {
          timers.push(setTimeout(() => card.classList.add('in'), 100 + i * stagger));
        });
        nums.forEach((numEl, i) => {
          const target = Number(numEl.dataset.target) || 0;
          const isInt = Number.isInteger(target);
          const begin = performance.now() + 200 + i * stagger;
          let rafId;
          function tick(now) {
            if (now < begin) { rafId = requestAnimationFrame(tick); rafs.push(rafId); return; }
            const t = Math.min(1, (now - begin) / duration);
            const eased = 1 - Math.pow(1 - t, 3);
            const value = target * eased;
            numEl.textContent = isInt ? Math.floor(value).toLocaleString() : value.toFixed(1);
            if (t < 1) { rafId = requestAnimationFrame(tick); rafs.push(rafId); }
            else numEl.textContent = isInt ? target.toLocaleString() : String(target);
          }
          rafId = requestAnimationFrame(tick);
          rafs.push(rafId);
        });
        return () => {
          rafs.forEach(cancelAnimationFrame);
          timers.forEach(clearTimeout);
        };
      },
      replay(el) {
        el.querySelectorAll('.stat-num').forEach(n => n.textContent = '0');
        el.querySelectorAll('.stat').forEach(n => n.classList.remove('in'));
        return this.init(el);
      }
    };
  };

  function escape(s) {
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
})(typeof window !== 'undefined' ? window : globalThis);

// === src/components/steps.js ===
'use strict';

/**
 * Stage.Steps — numbered tutorial steps (big numeral + label + body).
 *
 * Usage:
 *   Stage.register(Stage.Steps({
 *     section: 65,
 *     title: '65 · How it works',
 *     orientation: 'horizontal',   // 'horizontal' | 'vertical'
 *     steps: [
 *       { number: '01', label: 'Install',   body: 'Run npx stagecraft init.', icon: 'download' },
 *       { number: '02', label: 'Write',     body: 'Add slides to slides/.',  icon: 'edit' },
 *       { number: '03', label: 'Present',   body: 'Open in any browser.',    icon: 'present_to_all' }
 *     ],
 *     reveal: 'staggered'   // 'instant' | 'staggered' | 'per-click'
 *   }));
 *
 * Steps differ from ProcessFlow: ProcessFlow is about *flow* (arrows between
 * states); Steps is about *teaching* (numeral + explanation per step).
 *
 * Edit paths: steps[i].number / .label / .body / .icon
 */

(function (root) {
  const Stage = root.Stage = root.Stage || {};

  Stage.Steps = function (opts) {
    const stepsList = opts.steps || [];
    const reveal = opts.reveal || 'instant';
    const orientation = opts.orientation === 'vertical' ? 'vertical' : 'horizontal';

    const slide = {
      section: opts.section,
      title: opts.title,
      transition: opts.transition,
      render(el) {
        el.innerHTML = `
          <div class="steps steps--${orientation}" data-stage-key="Steps">
            ${stepsList.map((s, i) => `
              <div class="step-card" data-step="${i + 1}" data-stage-key="Steps/step[${i}]">
                <div class="step-numeral" data-stage-edit="steps[${i}].number">${escape(s.number || String(i + 1).padStart(2, '0'))}</div>
                <div class="step-content">
                  <div class="step-head">
                    ${s.icon ? `<span class="step-icon material-symbols-outlined" data-stage-edit="steps[${i}].icon">${escape(s.icon)}</span>` : ''}
                    <div class="step-label" data-stage-edit="steps[${i}].label">${escape(s.label || '')}</div>
                  </div>
                  ${s.body ? `<div class="step-body" data-stage-edit="steps[${i}].body">${escape(s.body)}</div>` : ''}
                </div>
              </div>
            `).join('')}
          </div>
        `;
        if (reveal === 'instant') {
          el.querySelectorAll('.step-card').forEach(n => n.classList.add('in'));
        }
      }
    };

    if (reveal === 'staggered') {
      slide.init = function (el) {
        return Stage.staggerIn(el.querySelectorAll('.step-card'), 200, 220);
      };
      slide.replay = function (el) {
        el.querySelectorAll('.step-card').forEach(n => n.classList.remove('in'));
        return this.init(el);
      };
    } else if (reveal === 'per-click') {
      slide.steps = stepsList.length;
      slide.onStep = function (el, step) {
        el.querySelectorAll('.step-card').forEach(n => {
          n.classList.toggle('in', Number(n.dataset.step) <= step);
        });
      };
    }

    return slide;
  };

  function escape(s) {
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
})(typeof window !== 'undefined' ? window : globalThis);

// === src/components/swot.js ===
'use strict';

/**
 * Stage.SWOT — 2x2 SWOT grid (Strengths / Weaknesses / Opportunities / Threats).
 *
 * Usage:
 *   Stage.register(Stage.SWOT({
 *     section: 5,
 *     title: '05 · SWOT',
 *     strengths:     ['fast iteration', 'strong brand', 'tier-1 talent'],
 *     weaknesses:    ['legacy code', 'fragmented data'],
 *     opportunities: ['agentic tooling', 'developer SaaS reset'],
 *     threats:       ['foundation model race', 'commoditisation'],
 *     reveal: 'staggered'   // 'instant' | 'staggered' | 'per-click'
 *   }));
 *
 * S = accent · W = amber · O = blue · T = red.
 *
 * Edit paths: strengths[i] / weaknesses[i] / opportunities[i] / threats[i]
 */

(function (root) {
  const Stage = root.Stage = root.Stage || {};

  Stage.SWOT = function (opts) {
    const strengths     = opts.strengths     || [];
    const weaknesses    = opts.weaknesses    || [];
    const opportunities = opts.opportunities || [];
    const threats       = opts.threats       || [];
    const reveal        = opts.reveal        || 'instant';

    const cells = [
      { key: 'strengths',     label: 'Strengths',     short: 'S', color: 'accent', items: strengths     },
      { key: 'weaknesses',    label: 'Weaknesses',    short: 'W', color: 'amber',  items: weaknesses    },
      { key: 'opportunities', label: 'Opportunities', short: 'O', color: 'blue',   items: opportunities },
      { key: 'threats',       label: 'Threats',       short: 'T', color: 'red',    items: threats       }
    ];

    const slide = {
      section: opts.section,
      title: opts.title,
      transition: opts.transition,
      render(el) {
        const cellHtml = cells.map((cell, idx) => {
          const items = cell.items.map((t, i) => `
            <li class="swot-item" data-stage-edit="${cell.key}[${i}]" data-stage-key="SWOT/${cell.key}/item[${i}]">${escape(t)}</li>
          `).join('');
          return `
            <div class="swot-cell swot-cell--${cell.color}"
                 data-quad-index="${idx}"
                 data-stage-key="SWOT/${cell.key}">
              <div class="swot-head">
                <span class="swot-letter">${cell.short}</span>
                <span class="swot-title">${escape(cell.label)}</span>
              </div>
              <ul class="swot-list">${items}</ul>
            </div>
          `;
        }).join('');

        el.innerHTML = `
          <div class="swot" data-stage-key="SWOT">
            ${cellHtml}
          </div>
        `;

        if (reveal === 'instant') {
          el.querySelectorAll('.swot-cell, .swot-item').forEach(n => n.classList.add('in'));
        }
      }
    };

    if (reveal === 'staggered') {
      slide.init = function (el) {
        const cellNodes = Array.from(el.querySelectorAll('.swot-cell'));
        const timers = [];
        cellNodes.forEach((cell, i) => {
          timers.push(setTimeout(() => {
            cell.classList.add('in');
            const items = cell.querySelectorAll('.swot-item');
            items.forEach((it, j) => {
              timers.push(setTimeout(() => it.classList.add('in'), 200 + j * 120));
            });
          }, 200 + i * 350));
        });
        return () => timers.forEach(clearTimeout);
      };
      slide.replay = function (el) {
        el.querySelectorAll('.swot-cell, .swot-item').forEach(n => n.classList.remove('in'));
        return this.init(el);
      };
    } else if (reveal === 'per-click') {
      slide.steps = cells.length;
      slide.onStep = function (el, step) {
        el.querySelectorAll('.swot-cell').forEach(n => {
          const idx = Number(n.dataset.quadIndex);
          const on = idx < step;
          n.classList.toggle('in', on);
          n.querySelectorAll('.swot-item').forEach(it => it.classList.toggle('in', on));
        });
      };
    }

    return slide;
  };

  function escape(s) {
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
})(typeof window !== 'undefined' ? window : globalThis);

